import java.util.TreeSet;

public class Solution {
    public static long solve(String s, long[] order, long k) {
        int n = s.length();
        TreeSet<Integer> stars = new TreeSet<>();
        long invalid = n * (n + 1) / 2;
        long total = n * (n + 1) / 2;
        for (int t = 0; t < n; t++) {
            int pos = (int) order[t];
            Integer prev = stars.floor(pos);
            Integer succ = stars.ceil(pos);
            stars.add(pos);
            int left = (prev == null) ? -1 : prev;
            int right = (succ == null) ? n : succ;
            int originalLength = right - left - 1;
            long originalContribution = originalLength * (originalLength + 1) / 2;
            int leftLength = pos - left - 1;
            int rightLength = right - pos - 1;
            long newContribution = (leftLength * (leftLength + 1) / 2) + (rightLength * (rightLength + 1) / 2);
            invalid = invalid - originalContribution + newContribution;
            long valid = total - invalid;
            if (valid >= k) {
                return t;
            }
        }
        return -1;
    }
}
